template <typename T, bool CHECKED>
class VerticalDWTPixelIO {
protected:
    int end;         
    int stride;      
    int initialize(const int sizeX, const int sizeY, int firstX, int firstY) {
      end = CHECKED ? (sizeY * sizeX + firstX) : 0;
      stride = sizeX;
      return firstX + sizeX * firstY;
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelWriter : VerticalDWTPixelIO<T, CHECKED> {
private:
    int next;   
public:
    void init(const int sizeX, const int sizeY, int firstX, int firstY) {
      if(firstX < sizeX) {
        next = this->initialize(sizeX, sizeY, firstX, firstY);
      } else {
        this->end = 0;
        this->stride = 0;
        next = 0;
      }
    }
    void writeInto(T * const output, const T & value) {
      if((!CHECKED) || (next != this->end)) {
        output[next] = value;
        next += this->stride;
      }
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelLoader : protected VerticalDWTPixelIO<const T, CHECKED> {
private:
    int last;  
public:
    void init(const int sizeX, const int sizeY, int firstX, int firstY) {
      int d = firstX;
      mirror(d, sizeX);
      last = this->initialize(sizeX, sizeY, d, firstY) - sizeX;
    }
    void clear() {
      this->end = 0;
      this->stride = 0;
      this->last = 0;
    }
    T loadFrom(const T * const input) {
      last += this->stride;
      if(CHECKED && (last == this->end)) {
        last -= 2 * this->stride;
        this->stride = -this->stride; 
      }
      return input[last];
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandIO : protected VerticalDWTPixelIO<T, CHECKED> {
protected:
    int strideHighToLow;
    int strideLowToHigh;
    int initialize(const int imageSizeX, const int imageSizeY, int firstX, int firstY) {
      int columnOffset = firstX / 2;
      int verticalStride;
      if(firstX & 1) {
        verticalStride = imageSizeX / 2;
        columnOffset += divRndUp(imageSizeX, 2) * divRndUp(imageSizeY, 2);
        strideLowToHigh = (imageSizeX * imageSizeY) / 2;
      } else {
        verticalStride = imageSizeX / 2 + (imageSizeX & 1);
        strideLowToHigh = divRndUp(imageSizeY, 2)  * imageSizeX;
      }
      strideHighToLow = verticalStride - strideLowToHigh;
      if(CHECKED) {
        end = columnOffset + (imageSizeY / 2) * verticalStride + (imageSizeY & 1) * strideLowToHigh;
      } else {
        end = 0;
      }
      return columnOffset + (firstY / 2) * verticalStride + (firstY & 1) * strideLowToHigh;
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandLoader : public VerticalDWTBandIO<const T, CHECKED> {
private:
    int last;  
    T updateAndLoad(const T * const input, const int & stride) {
      last += stride;
      if(CHECKED && (last == this->end)) {
        last -= (this->strideLowToHigh + this->strideHighToLow);
        const int temp = this->strideLowToHigh;
        this->strideLowToHigh = -this->strideHighToLow;
        this->strideHighToLow = -temp;
      }
      return input[last];
    }
public:
    void init(const int imageSizeX, const int imageSizeY, int firstX, const int firstY) {
      int d = firstX;
      mirror(d, imageSizeX);
      last = this->initialize(imageSizeX, imageSizeY, d, firstY);
      last -= (firstY & 1) ? this->strideLowToHigh : this->strideHighToLow; 
    }
    void clear() {
      this->end = 0;
      this->strideHighToLow = 0;
      this->strideLowToHigh = 0;
      this->last = 0;
    }
    T loadLowFrom(const T * const input) {
      return updateAndLoad(input, this->strideHighToLow);
    }
    T loadHighFrom(const T * const input) {
      return updateAndLoad(input, this->strideLowToHigh);
    }
